//vip.opstream16.com/20231029/36405_2bb62b0c/index.m3u8"},{"name":"03","slug":"","filename":"Night.Beauties.2023.Ep03.ViE.1080p.WEB-DL.H264.AAC.PPhim","link_embed":"https://vip.opstream16.com/share/e4df76144e798cb0077f3ce85d0a4e3e","link_m3u8":"https://vip.opstream16.com/20231029/36404_28ca9e63/index.m3u8"},{"name":"02","slug":"","filename":"Night.Beauties.2023.Ep02.ViE.1080p.WEB-DL.H264.AAC.PPhim","link_embed":"https://vip.opstream16.com/share/e6e4223421e4e4021aa3d7fa7925cebf","link_m3u8":"https://vip.opstream16.com/20231029/36403_394259c1/index.m3u8"},{"name":"01","slug":"","filename":"Night.Beauties.2023.Ep01.ViE.1080p.WEB-DL.H264.AAC.PPhim","link_embed":"https://vip.opstream16.com/share/9d09d0ad8bb694b73dc34bc34cf1ff15","link_m3u8":"https://vip.opstream16.com/20231029/36402_47ddee91/index.m3u8"}]}],"time":"42p/Tập","description":"<p>“Điệu nhảy khuynh thành” đánh dấu màn tái xuất của nữ diễn viên TVB vang bóng một thời - Trần Pháp Dung.&nbsp;</p><p>Thập niên 80, 90 của thế kỷ trước, kinh tế Hồng Kông “cất cánh”, theo đó, những địa điểm vui chơi, giải trí cũng mọc lên như nấm, nổi bật là hộp đêm Vạn Quốc Thành.&nbsp;</p><p>Nói tới Vạn Quốc Thành thì người đầu tiên phải nhắc đến là má mì Sa Tịnh Hà (Trần Pháp Dung đóng). Hà rất “mát tay” trong tuyển chọn và đào tạo vũ nữ. Hai đào cưng của cô là Văn Nhã Luân (Thái Khiết đóng) và Giang Khiết Nhi (Trần Tinh Dư đóng) chính là hai “át chủ bài”, giúp hộp đêm ngày càng ăn nên làm ra, biến nơi đây thành lựa chọn hàng đầu của những kẻ lắm tiền nhiều của, “đốt tiền” không tiếc tay.</p>","tmdb":{"type":"tv","id":"225738","season":1,"vote_average":5.5,"vote_count":2},"modified":"2024-12-20T10:30:53.000Z","_image_preserved":true},{"id":"654090bbe2f0dc639fd9c43a","_id":"654090bbe2f0dc639fd9c43a","title":"Đại Chiến Mai Mối","origin_name":"The Matchmakers","slug":"dai-chien-mai-moi","year":2023,"type":"series","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"}],"country":[{"id":"620a2300e0fc277084dfd6d2